SELECT visit_id, visit_date
FROM visits
WHERE visit_id = 0;

SELECT clinic_name
FROM clinics
WHERE clinic_id = 0;

SELECT SUM(visit_count) AS max_cumulative_visits
FROM (
    SELECT COUNT(visit_id) AS visit_count
    FROM visits
    GROUP BY doctor_id
) AS doctor_visits;

SELECT follow_up_id
FROM follow_ups
ORDER BY follow_up_date;
